import{_ as e,o as t,c as r,ag as l}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"介绍","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/index.md","filePath":"zh/guide/index.md","lastUpdated":1782658073000}'),n={name:"zh/guide/index.md"};function o(i,a,s,h,d,c){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><p>EasyYapi 是一个 IntelliJ IDEA 插件，基于 <a href="./docs#javadoc">Javadoc</a>、<a href="./docs#kdoc">KDoc</a> 和 <a href="./docs#scaladoc">ScalaDoc</a> 解析生成 API 文档。</p><p>你可以在保持代码零侵入的情况下得到相当完整的 API 文档，但是特殊的需求还是需要部分特殊的注释/注解配合。与之相对的是，你可以灵活地运用<a href="/zh/settings/">配置规则</a>来适应你的项目特性以减少代码侵入。</p><h2 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h2><ul><li><a href="./use">导出 API 文档</a></li><li><a href="./call">在 IDEA 中直接发起 API 请求</a></li><li><a href="/zh/settings/rule-authoring#内置-ai-助手">AI 辅助规则编写</a>——用自然语言描述需求，助手为你生成规则文件</li><li><a href="./call#api-dashboard">Postman 环境同步</a>——将 Postman 环境同步到 API Dashboard，支持内联编辑</li></ul><h2 id="开箱即用" tabindex="-1">开箱即用 <a class="header-anchor" href="#开箱即用" aria-label="Permalink to &quot;开箱即用&quot;">​</a></h2><p>EasyApi 开箱即用地支持标准 HTTP 框架（Spring MVC、WebFlux、JAX-RS、Feign）—— <strong>大多数项目无需自定义规则</strong>。对于扫描器无法察觉的自定义框架行为（例如要求添加请求头的 <code>jakarta.servlet.Filter</code>，或将每个响应包装在信封中的 <code>ResponseBodyAdvice</code>），可使用内置的 AI 助手或外部 skill 来检测并生成规则。完整的自定义模式目录请参见 <a href="https://github.com/tangcent/easy-yapi/blob/master/docs/knowledge-base/rule-guide.md" target="_blank" rel="noreferrer">Rule Authoring Guide</a>。</p><h2 id="支持项列表" tabindex="-1">支持项列表 <a class="header-anchor" href="#支持项列表" aria-label="Permalink to &quot;支持项列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>默认支持</th><th>额外支持</th></tr></thead><tbody><tr><td>语言</td><td>Java, Kotlin</td><td>Scala</td></tr><tr><td>Web 框架</td><td><a href="https://spring.io/" target="_blank" rel="noreferrer">Spring</a>、<a href="https://docs.spring.io/spring-framework/reference/web/webflux.html" target="_blank" rel="noreferrer">Spring WebFlux</a>、<a href="https://spring.io/projects/spring-cloud-openfeign" target="_blank" rel="noreferrer">Feign</a>、<a href="https://www.oracle.com/technical-resources/articles/java/jax-rs.html" target="_blank" rel="noreferrer">JAX-RS</a> (<a href="https://quarkus.io/" target="_blank" rel="noreferrer">Quarkus</a> / <a href="https://eclipse-ee4j.github.io/jersey/" target="_blank" rel="noreferrer">Jersey</a>)、<a href="https://grpc.io/" target="_blank" rel="noreferrer">gRPC</a></td><td>-</td></tr><tr><td>导出渠道</td><td><a href="./export2postman">Postman</a>、<a href="./export2yapi">YApi</a>、<a href="./export2markdown">Markdown</a>、<a href="./export2curl">cURL</a>、<a href="./export2httpclient">HttpClient</a></td><td>-</td></tr><tr><td>常用框架</td><td>javax.validation、Jakarta Validation、Jackson、Gson</td><td><a href="https://swagger.io/" target="_blank" rel="noreferrer">Swagger</a>、Fastjson</td></tr><tr><td>功能特性</td><td><a href="./call">API 调用</a>、<a href="./call#api-dashboard">API Dashboard</a>、<a href="./call#编辑器行标记导航">编辑器行标记导航</a>、<a href="./script-executor">脚本执行器</a>、<a href="/zh/settings/rule-authoring">AI 辅助规则编写</a></td><td>Spring Actuator</td></tr></tbody></table><h2 id="社区" tabindex="-1">社区 <a class="header-anchor" href="#社区" aria-label="Permalink to &quot;社区&quot;">​</a></h2><ul><li>讨论<a href="https://github.com/tangcent/easy-yapi/issues?q=label%3Aenhancement" target="_blank" rel="noreferrer">新功能</a>或提交 <a href="https://github.com/tangcent/easy-yapi/issues?q=label%3Abug" target="_blank" rel="noreferrer">BUG</a>: <a href="https://github.com/tangcent/easy-yapi/issues" target="_blank" rel="noreferrer">Issues</a></li><li>开发<a href="https://github.com/tangcent/easy-yapi/pulls?q=+label%3Aenhancement" target="_blank" rel="noreferrer">新功能</a>或修复 <a href="https://github.com/tangcent/easy-yapi/pulls?q=+label%3Abug" target="_blank" rel="noreferrer">BUG</a>: <a href="https://github.com/tangcent/easy-yapi/pulls" target="_blank" rel="noreferrer">Pull Requests</a></li></ul><h2 id="贡献者" tabindex="-1">贡献者 <a class="header-anchor" href="#贡献者" aria-label="Permalink to &quot;贡献者&quot;">​</a></h2><a href="https://github.com/tangcent/easy-yapi/graphs/contributors"><img src="https://contrib.rocks/image?repo=tangcent/easy-yapi"></a>',13)])])}const f=e(n,[["render",o]]);export{g as __pageData,f as default};
